mother.audio.stt.FasterWhisperSTT.transcribe_wav — def transcribe_wav(self, wav_path, language)

    def transcribe_wav(self, wav_path: str, language: Optional[str] = None) -> str:
        lang = language or self.cfg.language or "en"
        beam = getattr(self.cfg, "beam_size", 5)

        def _run(vad: bool):
            return self.model.transcribe(
                wav_path,
                language=lang,
                vad_filter=vad,
                beam_size=beam,
                temperature=0.0,
            )

        try:
            segments, info = _run(vad=True)
        except Exception:
            segments, info = _run(vad=False)
        texts: list[str] = []
        for seg in segments:
            if getattr(seg, "text", None):
                texts.append(seg.text)
        return " ".join(texts).strip()

