def _fire_due_reminders() -> None:
    now = datetime.now()
    with _lock:
        reminders = _load()
        changed = False
        for r in reminders:
            if r.get("fired"):
                continue
            try:
                trigger = datetime.fromisoformat(r["trigger_iso"])
            except (KeyError, ValueError):
                continue
            if trigger <= now:
                r["fired"] = True
                changed = True
                text = r.get("text", "reminder")
                _fire(r.get("user_id", ""), text)
        if changed:
            _save(reminders)

