Normalize peak to target_peak to even out volume across clips.

def normalize(audio: np.ndarray, target_peak: float = 0.9) -> np.ndarray:
    """Normalize peak to target_peak to even out volume across clips."""
    peak = np.abs(audio).max()
    if peak < 1e-6:
        return audio
    return audio * (target_peak / peak)

