def _build_watched_paths(roots: Iterable[str]) -> list[Path]:
    """Resolve the directory roots we want watchdog to observe."""
    out: list[Path] = []
    for r in roots:
        p = (_PROJECT_ROOT / r).resolve()
        if p.exists() and p.is_dir():
            out.append(p)
    return out
